SELECT * 
FROM rooms 
WHERE room_id = 1;

SELECT AVG(conflict_count) AS average_conflicts_per_course
FROM (
    SELECT class_id, COUNT(*) AS conflict_count
    FROM conflicts
    GROUP BY class_id
) AS course_conflicts;

SELECT * 
FROM rooms 
WHERE availability_status = 'available';

SELECT i.instructor_name
FROM instructors i
JOIN departments d ON i.instructor_id = d.department_head_id;

SELECT class_id, COUNT(*) AS num_conflicts
FROM conflicts
GROUP BY class_id;

SELECT class_id
FROM conflicts
WHERE conflict_type IS NOT NULL;
